1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
3	const BLOCK_OF_3_BASE_PREMIUM = 60;
4	
5	const BASE_PREMIUM: Record<string, number> = {
6	  sword: 100,
7	  amulet: 60,
8	  staff: 80,
9	  potion: 40,
10	  rune: 25,
11	};
12	
13	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
14	
15	type Item = { type: string };
16	type Step = { op: "quote"; items: Item[] };
17	type Scenario = { customer: { yearsWithMHPCO: number }; steps: Step[] };
18	type QuoteResult = { premium: number };
19	
20	const withFirstInsurance = (base: number): number =>
21	  base + base * FIRST_INSURANCE_SURCHARGE_RATE;
22	
23	const itemPremium = (item: Item): number =>
24	  withFirstInsurance(BASE_PREMIUM[item.type]);
25	
26	const componentGroupPremium = (type: string, count: number): number => {
27	  if (count === 3) return withFirstInsurance(BLOCK_OF_3_BASE_PREMIUM);
28	  return count * withFirstInsurance(BASE_PREMIUM[type]);
29	};
30	
31	const sumItemPremiums = (items: Item[]): number => {
32	  const componentCounts = new Map<string, number>();
33	  let total = 0;
34	  for (const item of items) {
35	    if (COMPONENT_TYPES.has(item.type)) {
36	      componentCounts.set(item.type, (componentCounts.get(item.type) ?? 0) + 1);
37	    } else {
38	      total += itemPremium(item);
39	    }
40	  }
41	  for (const [type, count] of componentCounts) {
42	    total += componentGroupPremium(type, count);
43	  }
44	  return total;
45	};
46	
47	const quoteStep = (step: Step): QuoteResult => ({
48	  premium: sumItemPremiums(step.items) + PROCESSING_FEE,
49	});
50	
51	export const runScenario = (scenario: Scenario): { results: QuoteResult[] } => ({
52	  results: scenario.steps.map(quoteStep),
53	});
