const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);

const componentGroupPremium = (type: string, count: number): number =>
  count === 3
    ? withFirstInsurance(BLOCK_OF_3_BASE_PREMIUM)
    : count * withFirstInsurance(BASE_PREMIUM[type]);

const countByType = (items: Item[]): Map<string, number> => {
  const counts = new Map<string, number>();
  for (const item of items) {
    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
  }
  return counts;
};

const sumComponentPremiums = (components: Item[]): number => {
  let total = 0;
  for (const [type, count] of countByType(components)) {
    total += componentGroupPremium(type, count);
  }
  return total;
};

const sumMainItemPremiums = (mainItems: Item[]): number =>
  mainItems.reduce((sum, item) => sum + itemPremium(item), 0);

const sumItemPremiums = (items: Item[]): number => {
  const components = items.filter(isComponent);
  const mainItems = items.filter((item) => !isComponent(item));
  return sumMainItemPremiums(mainItems) + sumComponentPremiums(components);
};
